61		    
62	      input wire [15:0] max_signal_len_th,
63		    // from wifi rx
64		    input wire [(C_M00_AXIS_TDATA_WIDTH-1) : 0] data_from_acc,
65		    input wire data_ready_from_acc,
66	      input wire [7:0] pkt_rate,
67			  input wire [15:0] pkt_len,
68	      input wire sig_valid,
