81		);
82		
83		  localparam [0:0]   WAIT_S2MM_INTR =                    1'b0,
84	                       COUNT_TO_TOP  =                     1'b1;
85	                       
86		  localparam [2:0]   WAIT_FOR_PKT =                      3'b000,
87	                       DMA_HEADER0_INSERT  =               3'b001,
88	                       DMA_HEADER1_INSERT_AND_START =      3'b010,
89	                       WAIT_FILTER_FLAG =                  3'b011,
90	                       WAIT_DMA_TLAST =                    3'b100,
91	                       WAIT_RST_DONE =                     3'b101;
92	
93	    `DEBUG_PREFIX reg [2:0] rx_state;
94	    reg [2:0] old_rx_state;
95	    reg start_m_axis;
96	    reg [(C_M00_AXIS_TDATA_WIDTH-1) : 0] data_to_m_axis;
97	    reg data_ready_to_m_axis;
98	    reg [2:0] rst_count;
