109	    
110		  assign data_to_m_axis_out =       (start_1trans_mode==3'b101)? data_to_m_axis:( (src_sel==1'b0)?data_from_acc:rf_iq );
111	    assign data_ready_to_m_axis_out = (start_1trans_mode==3'b101)? data_ready_to_m_axis:( (src_sel==1'b0)?data_ready_from_acc:rf_iq_valid );
112	
113	    assign rx_pkt_sn_plus_one = (rx_state==WAIT_FILTER_FLAG && block_rx_dma_to_ps_valid==1 && block_rx_dma_to_ps==0);
114	    
115	    always @( start_1trans_mode,sig_valid,fcs_valid,start_1trans_ext_trigger,start_m_axis)
116	    begin
117	       case (start_1trans_mode)
118	          3'b000 : begin
119	                        start_1trans_to_m_axis = fcs_valid;
120	                   end
121	          3'b001 : begin
122	                        start_1trans_to_m_axis = sig_valid;
123	                   end
124	          3'b010 : begin
125	                        start_1trans_to_m_axis = start_1trans_ext_trigger;
126	                   end
127	          3'b011 : begin
128	                        start_1trans_to_m_axis = 0;
129	                   end
130	          3'b100 : begin
131	                        start_1trans_to_m_axis = 0;
132	                   end
133	          3'b101 : begin
134	                        start_1trans_to_m_axis = start_m_axis;
135	                   end
136	          3'b110 : begin
137	                        start_1trans_to_m_axis = 0;
138	                   end
139	          3'b111 : begin
140	                        start_1trans_to_m_axis = 0;
141	                   end
142	          default: begin
143	                        start_1trans_to_m_axis = 0;
144	                   end
145	       endcase
146	    end
147	
148	    //lock tsf runtime value by sig_valid
149	    always @( posedge clk )
150	    begin
151	      if (!rstn) begin
152	        tsf_val_lock_by_sig<=0;
153	      end 
154	      else begin
155	        if (sig_valid)
156	          tsf_val_lock_by_sig<=tsf_runtime_val;
157	        else
158	          tsf_val_lock_by_sig<=tsf_val_lock_by_sig;
159	      end
160	    end
161	
162	    //state machine to control m_axis to ARM
163	    always @(posedge clk)                                             
164	    begin
165	      if (!rstn) begin
166	          rst_count <= 0;
167	          monitor_num_dma_symbol_to_ps<=0;
168	          m_axis_rst<=0;
169	          m_axis_tlast_auto_recover<=0;
170	          data_to_m_axis <= 0;
171	          data_ready_to_m_axis <= 0;
172	          start_m_axis <= 0;
173	          rx_state <= WAIT_FOR_PKT;
174	          old_rx_state <= WAIT_FOR_PKT;
175	          timeout_timer_1M<=0;
176	          s2mm_intr_reg <= 0;
177	      end
178	      else begin
179	        old_rx_state <= rx_state;
180	        s2mm_intr_reg <= s2mm_intr;
181	        count_top_scale <= (count_top*`COUNT_SCALE);
182	        count_top_scale_plus1 <= (count_top_scale+1);
183	        case (rx_state)
184	          WAIT_FOR_PKT: begin
185	            timeout_timer_1M<=0;
186	            rst_count <= 0;
187	            data_to_m_axis <= 0;
188	            data_ready_to_m_axis <= 0;
189	            start_m_axis <= 0;
190	            m_axis_rst<=0;
191	            m_axis_tlast_auto_recover<=0;
192	            if ( sig_valid && (ht_unsupport==0) && (pkt_len>=14 && pkt_len<=max_signal_len_th) ) begin
193	              monitor_num_dma_symbol_to_ps<=( pkt_len[15:3] + (pkt_len[2:0]!=0) ) + 2; // 2 for tsf, rf_info and rate/len insertion at the beginnig;
194	              rx_state <= DMA_HEADER0_INSERT;
195	            end
196	          end
197	
198	          DMA_HEADER0_INSERT: begin // data is calculated by calc_phy_header C program
199	            // timeout_timer_1M<=timeout_timer_1M;
200	            // rst_count <= rst_count;
201	            //data_to_m_axis <= (pad_test==1?64'h0123456789abcdef:tsf_val_lock_by_sig);
202	            data_to_m_axis <= tsf_val_lock_by_sig;
203	            data_ready_to_m_axis <= 1;
204	            // start_m_axis <= start_m_axis;
205	            // monitor_num_dma_symbol_to_ps<=monitor_num_dma_symbol_to_ps;
206	            // m_axis_rst<=m_axis_rst;
207	            // m_axis_tlast_auto_recover<=m_axis_tlast_auto_recover;
208	            rx_state <= DMA_HEADER1_INSERT_AND_START;
209	          end
210	
211	          DMA_HEADER1_INSERT_AND_START: begin // data is calculated by calc_phy_header C program
212	            // timeout_timer_1M<=timeout_timer_1M;
213	            // rst_count <= rst_count;
214	            //data_to_m_axis <= (pad_test==1?64'hfedcba9876543210:{11'd0, pkt_rate[7],pkt_rate[3:0],pkt_len, 8'd0, gpio_status_lock_by_sig_valid, 5'd0, rssi_half_db_lock_by_sig_valid});
215	            data_to_m_axis <= {phase_offset_taken[7:0], ht_aggr_last, ht_aggr, ht_sgi, pkt_rate[7],pkt_rate[3:0],pkt_len, 8'd1, gpio_status_lock_by_sig_valid, 5'd0, rssi_half_db_lock_by_sig_valid};//8'd1 next to gpio_status_lock_by_sig_valid is for pkt exist flag in rx dma buffer
216	            // data_ready_to_m_axis <= data_ready_to_m_axis;
217	            // start_m_axis <= start_m_axis;
218	            // monitor_num_dma_symbol_to_ps<=monitor_num_dma_symbol_to_ps;
219	            // m_axis_rst<=m_axis_rst;
220	            // m_axis_tlast_auto_recover<=m_axis_tlast_auto_recover;
221	            rx_state <= WAIT_FILTER_FLAG;
222	          end
223	
224	          WAIT_FILTER_FLAG: begin
225	            // rst_count <= rst_count;
226	            data_to_m_axis <= data_from_acc;
227	            data_ready_to_m_axis <= data_ready_from_acc;
228	            // monitor_num_dma_symbol_to_ps<=monitor_num_dma_symbol_to_ps;
229	            if ( (timeout_timer_1M>m_axis_tlast_auto_recover_timeout_top) && m_axis_tlast_auto_recover_enable) begin//tlast timeout, let's generate a fake tlast to release ARM dma and reset our m_axis
230	              // start_m_axis <= start_m_axis;
231	              // timeout_timer_1M<=timeout_timer_1M;
232	              m_axis_rst<=1;
233	              m_axis_tlast_auto_recover<=1;
234	              rx_state <= WAIT_RST_DONE;
235	            end else begin
236	              // m_axis_tlast_auto_recover<=m_axis_tlast_auto_recover;
237	              if (block_rx_dma_to_ps_valid==1 && block_rx_dma_to_ps==0) begin
238	                timeout_timer_1M<=0;
239	                start_m_axis <= 1;
240	                // m_axis_rst<=m_axis_rst;
241	                rx_state <= WAIT_DMA_TLAST;
242	              end else if (block_rx_dma_to_ps_valid==1 && block_rx_dma_to_ps==1) begin
243	                // timeout_timer_1M<=timeout_timer_1M;
244	                // start_m_axis <= start_m_axis;
245	                m_axis_rst<=1;
246	                rx_state <= WAIT_RST_DONE;
247	              end else begin
248	                timeout_timer_1M<=(tsf_pulse_1M?(timeout_timer_1M+1):timeout_timer_1M);
249	                // start_m_axis <= start_m_axis;
250	                // m_axis_rst<=m_axis_rst;
251	                // rx_state <= rx_state;
252	              end
253	            end
254	          end
255	
256	          WAIT_DMA_TLAST: begin
257	            // rst_count <= rst_count;
258	            data_to_m_axis <= data_from_acc;
259	            data_ready_to_m_axis <= data_ready_from_acc;
260	            start_m_axis <= 0;
261	            // monitor_num_dma_symbol_to_ps<=monitor_num_dma_symbol_to_ps;
262	            if ( (timeout_timer_1M>m_axis_tlast_auto_recover_timeout_top) && m_axis_tlast_auto_recover_enable) begin//tlast timeout, let's generate a fake tlast to release ARM dma and reset our m_axis
263	              // timeout_timer_1M<=timeout_timer_1M;
264	              m_axis_rst<=1;
265	              m_axis_tlast_auto_recover<=1;
266	              rx_state <= WAIT_RST_DONE;
267	            end else begin
268	              timeout_timer_1M<=(tsf_pulse_1M?(timeout_timer_1M+1):timeout_timer_1M);
269	              // m_axis_rst<=m_axis_rst;
270	              // m_axis_tlast_auto_recover<=m_axis_tlast_auto_recover;
271	              rx_state <= (m_axis_tlast?WAIT_FOR_PKT:rx_state);
272	            end
273	          end
274	
275	          WAIT_RST_DONE: begin
276	            // timeout_timer_1M<=timeout_timer_1M;
277	            m_axis_tlast_auto_recover<=0;
278	            rst_count <= rst_count+1;
279	            data_to_m_axis <= 0;
280	            data_ready_to_m_axis <= 0;
281	            // start_m_axis <= start_m_axis;
282	            monitor_num_dma_symbol_to_ps<=0;
283	            if (rst_count==7) begin
284	              m_axis_rst<=0;
285	              rx_state <= WAIT_FOR_PKT;
286	            end else begin
287	              m_axis_rst<=m_axis_rst;
288	              rx_state <= rx_state;
289	            end
290	          end
291	        endcase
292	      end
293	    end
294	
295	    // process to generate delayed interrupt after receive s2mm_intr
296	    always @(posedge clk) begin                                                                     
297	      if ( (!rstn) || (s2mm_intr==1 && s2mm_intr_reg==0) ) begin
298	        count    <= 0;
299	        rx_pkt_intr<=0;
300	      end else begin
301	        count <= (count!=count_top_scale_plus1?(count+1):count);
302	        rx_pkt_intr <= (count==count_top_scale);
303	      end
304	    end
305	
306		endmodule
